     1→/**
     2→ * WikiLinkNode - Custom Lexical Node for Wiki-style Links
     3→ *
     4→ * Renders [[Note Title]] links with:
     5→ * - Visual distinction between valid/broken links
     6→ * - Click handler for broken links to create notes
     7→ * - Semantic color tokens (no hardcoded colors)
     8→ */
     9→
    10→import type {
    11→  EditorConfig,
    12→  LexicalNode,
    13→  NodeKey,
    14→  SerializedTextNode,
    15→  Spread,
    16→} from 'lexical';
    17→import { TextNode } from 'lexical';
    18→import type { Note } from '../../types/notes';
    19→
    20→export type SerializedWikiLinkNode = Spread<
    21→  {
    22→    linkTitle: string;
    23→    isBroken: boolean;
    24→    blockId?: string;
    25→  },
    26→  SerializedTextNode
    27→>;
    28→
    29→/**
    30→ * WikiLinkNode - Custom text node for wiki-style links
    31→ * Extends TextNode to preserve text editing capabilities
    32→ */
    33→export class WikiLinkNode extends TextNode {
    34→  __linkTitle: string;
    35→  __isBroken: boolean;
    36→  __blockId: string | undefined;
    37→
    38→  static getType(): string {
    39→    return 'wiki-link';
    40→  }
    41→
    42→  static clone(node: WikiLinkNode): WikiLinkNode {
    43→    return new WikiLinkNode(node.__linkTitle, node.__isBroken, node.__blockId, node.__text, node.__key);
    44→  }
    45→
    46→  constructor(linkTitle: string, isBroken: boolean, blockId?: string, text?: string, key?: NodeKey) {
    47→    super(text ?? `[[${linkTitle}]]`, key);
    48→    this.__linkTitle = linkTitle;
    49→    this.__isBroken = isBroken;
    50→    this.__blockId = blockId;
    51→  }
    52→
    53→  createDOM(config: EditorConfig): HTMLElement {
    54→    const element = super.createDOM(config);
    55→    element.className = this.__isBroken
    56→      ? 'wiki-link wiki-link-broken'
    57→      : 'wiki-link wiki-link-valid';
    58→
    59→    // Store block ID as data attribute
    60→    if (this.__blockId) {
    61→      element.setAttribute('data-block-id', this.__blockId);
    62→    }
    63→
    64→    // Accessibility
    65→    const linkTarget = this.__blockId
    66→      ? `${this.__linkTitle}#${this.__blockId}`
    67→      : this.__linkTitle;
    68→
    69→    element.setAttribute(
    70→      'aria-label',
    71→      this.__isBroken
    72→        ? `Broken link to ${linkTarget}. Click to create note.`
    73→        : `Link to ${linkTarget}`
    74→    );
    75→
    76→    // Cursor pointer for clickable links
    77→    element.style.cursor = 'pointer';
    78→
    79→    return element;
    80→  }
    81→
    82→  updateDOM(
    83→    prevNode: WikiLinkNode,
    84→    dom: HTMLElement,
    85→    config: EditorConfig
    86→  ): boolean {
    87→    // Update class if broken state changed
    88→    if (prevNode.__isBroken !== this.__isBroken) {
    89→      dom.className = this.__isBroken
    90→        ? 'wiki-link wiki-link-broken'
    91→        : 'wiki-link wiki-link-valid';
    92→
    93→      // Update aria-label
    94→      dom.setAttribute(
    95→        'aria-label',
    96→        this.__isBroken
    97→          ? `Broken link to ${this.__linkTitle}. Click to create note.`
    98→          : `Link to ${this.__linkTitle}`
    99→      );
   100→    }
   101→
   102→    // Update text content if changed
   103→    const isUpdated = super.updateDOM(prevNode as this, dom, config);
   104→    return isUpdated;
   105→  }
   106→
   107→  static importJSON(serializedNode: SerializedWikiLinkNode): WikiLinkNode {
   108→    const node = $createWikiLinkNode(
   109→      serializedNode.linkTitle,
   110→      serializedNode.isBroken,
   111→      serializedNode.blockId
   112→    );
   113→    node.setFormat(serializedNode.format);
   114→    node.setDetail(serializedNode.detail);
   115→    node.setMode(serializedNode.mode);
   116→    node.setStyle(serializedNode.style);
   117→    return node;
   118→  }
   119→
   120→  exportJSON(): SerializedWikiLinkNode {
   121→    return {
   122→      ...super.exportJSON(),
   123→      linkTitle: this.__linkTitle,
   124→      isBroken: this.__isBroken,
   125→      blockId: this.__blockId,
   126→      type: 'wiki-link',
   127→      version: 1,
   128→    };
   129→  }
   130→
   131→  getLinkTitle(): string {
   132→    return this.__linkTitle;
   133→  }
   134→
   135→  getIsBroken(): boolean {
   136→    return this.__isBroken;
   137→  }
   138→
   139→  setIsBroken(isBroken: boolean): void {
   140→    const writable = this.getWritable();
   141→    writable.__isBroken = isBroken;
   142→  }
   143→
   144→  getBlockId(): string | undefined {
   145→    return this.__blockId;
   146→  }
   147→
   148→  setBlockId(blockId: string | undefined): void {
   149→    const writable = this.getWritable();
   150→    writable.__blockId = blockId;
   151→  }
   152→}
   153→
   154→/**
   155→ * Helper function to create WikiLinkNode
   156→ */
   157→export function $createWikiLinkNode(
   158→  linkTitle: string,
   159→  isBroken: boolean,
   160→  blockId?: string
   161→): WikiLinkNode {
   162→  return new WikiLinkNode(linkTitle, isBroken, blockId);
   163→}
   164→
   165→/**
   166→ * Type guard for WikiLinkNode
   167→ */
   168→export function $isWikiLinkNode(
   169→  node: LexicalNode | null | undefined
   170→): node is WikiLinkNode {
   171→  return node instanceof WikiLinkNode;
   172→}
   173→
   174→/**
   175→ * Utility: Check if a link title is broken (doesn't resolve to a note)
   176→ */
   177→export function isLinkBroken(linkTitle: string, allNotes: Record<string, Note>): boolean {
   178→  const notesArray = Object.values(allNotes);
   179→  const titleLower = linkTitle.toLowerCase();
   180→
   181→  // Link is NOT broken if we find an exact or partial match
